740: func validateCronJobSpec(spec, oldSpec *batch.CronJobSpec, fldPath *field.Path, opts apivalidation.PodValidationOptions) field.ErrorList {
741: 	allErrs := field.ErrorList{}
742: 
743: 	if len(spec.Schedule) == 0 {
744: 		allErrs = append(allErrs, field.Required(fldPath.Child("schedule"), ""))
745: 	} else {
746: 		allowTZInSchedule := false
747: 		if oldSpec != nil {
748: 			allowTZInSchedule = strings.Contains(oldSpec.Schedule, "TZ")
749: 		}
750: 		allErrs = append(allErrs, validateScheduleFormat(spec.Schedule, allowTZInSchedule, spec.TimeZone, fldPath.Child("schedule"))...)
751: 	}
752: 
753: 	if spec.StartingDeadlineSeconds != nil {
754: 		allErrs = append(allErrs, apivalidation.ValidateNonnegativeField(int64(*spec.StartingDeadlineSeconds), fldPath.Child("startingDeadlineSeconds"))...)
755: 	}
756: 
757: 	if oldSpec == nil || !ptr.Equal(oldSpec.TimeZone, spec.TimeZone) {
758: 		allErrs = append(allErrs, validateTimeZone(spec.TimeZone, fldPath.Child("timeZone"))...)
759: 	}
760: 
761: 	allErrs = append(allErrs, validateConcurrencyPolicy(&spec.ConcurrencyPolicy, fldPath.Child("concurrencyPolicy"))...)
762: 	allErrs = append(allErrs, ValidateJobTemplateSpec(&spec.JobTemplate, fldPath.Child("jobTemplate"), opts)...)
763: 
764: 	if spec.SuccessfulJobsHistoryLimit != nil {
765: 		// zero is a valid SuccessfulJobsHistoryLimit
766: 		allErrs = append(allErrs, apivalidation.ValidateNonnegativeField(int64(*spec.SuccessfulJobsHistoryLimit), fldPath.Child("successfulJobsHistoryLimit"))...)
767: 	}
768: 	if spec.FailedJobsHistoryLimit != nil {
769: 		// zero is a valid SuccessfulJobsHistoryLimit
770: 		allErrs = append(allErrs, apivalidation.ValidateNonnegativeField(int64(*spec.FailedJobsHistoryLimit), fldPath.Child("failedJobsHistoryLimit"))...)
771: 	}
772: 
773: 	return allErrs
774: }
