776: func validateConcurrencyPolicy(concurrencyPolicy *batch.ConcurrencyPolicy, fldPath *field.Path) field.ErrorList {
777: 	allErrs := field.ErrorList{}
778: 	switch *concurrencyPolicy {
779: 	case batch.AllowConcurrent, batch.ForbidConcurrent, batch.ReplaceConcurrent:
780: 		break
781: 	case "":
782: 		allErrs = append(allErrs, field.Required(fldPath, ""))
783: 	default:
784: 		validValues := []batch.ConcurrencyPolicy{batch.AllowConcurrent, batch.ForbidConcurrent, batch.ReplaceConcurrent}
785: 		allErrs = append(allErrs, field.NotSupported(fldPath, *concurrencyPolicy, validValues))
786: 	}
787: 
788: 	return allErrs
789: }
