791: func validateScheduleFormat(schedule string, allowTZInSchedule bool, timeZone *string, fldPath *field.Path) field.ErrorList {
792: 	allErrs := field.ErrorList{}
793: 	if _, err := cron.ParseStandard(schedule); err != nil {
794: 		allErrs = append(allErrs, field.Invalid(fldPath, schedule, err.Error()))
795: 	}
796: 	switch {
797: 	case allowTZInSchedule && strings.Contains(schedule, "TZ") && timeZone != nil:
798: 		allErrs = append(allErrs, field.Invalid(fldPath, schedule, "cannot use both timeZone field and TZ or CRON_TZ in schedule"))
799: 	case !allowTZInSchedule && strings.Contains(schedule, "TZ"):
800: 		allErrs = append(allErrs, field.Invalid(fldPath, schedule, "cannot use TZ or CRON_TZ in schedule, use timeZone field instead"))
801: 	}
802: 
803: 	return allErrs
804: }
